codeExamples.javascript:
const baseUrl = 'http://localhost:3010';
const path = '/auth/credentials';
const url = `${baseUrl}${path}`;

const response = await fetch(url, {
  method: 'POST',
  headers: {
    'Authorization': 'Bearer 6782dfcaa7e7f88621b4e6116d2de78e81b7ca8287b17ed01649684ec277aed3',
    'Content-Type': 'application/json'
  },
  body: JSON.stringify({
      "name": "Test Foundry Server",
      "foundryUrl": "http://localhost:30000",
      "foundryUsername": "testgm",
      "foundryPassword": "testpassword123"
    })
});
const data = await response.json();
console.log(data);

